export function publishEvent(workspaceId: string, type: string, payload: unknown, userId?: string, entity?: string, entityId?: string) {
  const id = uid("evt_");
  const t = now();
  db.prepare(
    "INSERT INTO realtime_events (id, workspace_id, type, payload, actor_id, entity, entity_id, created_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?)"
  ).run(id, workspaceId, type, JSON.stringify(payload), userId || null, entity || null, entityId || null, t);
  return { id, workspaceId, type, payload, userId, entity, entityId, createdAt: t };
}

