+ *
+ * Fuses marketing data (campaigns, leads/contacts) with sales data (deals,
+ * revenue, risk) into a single alignment view: a lead→deal→revenue funnel,
+ * shared KPIs, marketing-attributed revenue, and SLA gap detection.
+ *
+ * Reuses the existing intelligence modules (attribution rollup, deal risk)
+ * so it stays wired to the live SQLite data.
+ */
+import { db, now } from "@/lib/db";
+import { attributionRollup } from "@/lib/attribution";
+import { scoreAllDeals } from "@/lib/deal-intel";
+
+export interface SmarketingFunnelStage {
+  key: string;
+  label: string;
+  value: number;
+}
+
+export interface SmarketingCampaignRow {
+  id: string;
+  name: string;
+  status: string;
+  spent: number;
+  conversions: number;
+  cpl: number;
+}
+
+export interface SmarketingRiskSummary {
+  open: number;
+  safe: number;
+  watch: number;
+  atRisk: number;
+  critical: number;
+  top: { dealId: string; name: string; value: number; level: string; risk: number }[];
+}
+
+export interface SmarketingMetrics {
+  generated_at: number;
+  marketing: {
+    campaigns_total: number;
+    campaigns_active: number;
+    budget_total: number;
+    spent_total: number;
+    impressions: number;
+    clicks: number;
+    conversions: number;
+    ctr: number;
+    cpl: number;
+  };
+  sales: {
+    pipeline_value: number;
+    won_value: number;
+    lost_value: number;
+    open_deals: number;
+    won_deals: number;
+    lost_deals: number;
+    win_rate: number;
+    avg_deal_size: number;
+  };
+  leads: {
+    total: number;
+    by_status: Record<string, number>;
+    mql: number;
+    sql: number;
+  };
+  alignment: {
+    lead_to_deal_rate: number;
+    deal_to_won_rate: number;
+    marketing_sourced_revenue: number;
+    marketing_roi: number;
+    cost_per_acquisition: number;
+    cac_payback_ratio: number;
+    unworked_leads: number;
+    stale_open_deals: number;
+  };
+  funnel: SmarketingFunnelStage[];
+  top_campaigns: SmarketingCampaignRow[];
+  risk: SmarketingRiskSummary;
+  channel_attribution: {
+    model: string;
+    total_attributed: number;
+    deals_attributed: number;
+    channels: { channel: string; credit: number; share: number }[];
+  };
+}
+
+function parseMetrics(m: unknown): { impressions: number; clicks: number; conversions: number } {
+  if (!m) return { impressions: 0, clicks: 0, conversions: 0 };
+  const o = typeof m === "string" ? (() => { try { return JSON.parse(m); } catch { return {}; } })() : (m as Record<string, unknown>);
+  return {
+    impressions: Number(o.impressions) || 0,
+    clicks: Number(o.clicks) || 0,
+    conversions: Number(o.conversions) || 0,
+  };
+}
+
+export function getSmarketing(): SmarketingMetrics {
+  const t = now();
+  const DAY = 1000 * 60 * 60 * 24;
+
+  // ── Marketing: campaigns ──
+  const campaigns = db
+    .prepare(`SELECT id, name, status, budget, spent, metrics FROM campaigns`)
+    .all() as Record<string, unknown>[];
+
+  let budgetTotal = 0;
+  let spentTotal = 0;
+  let impressions = 0;
+  let clicks = 0;
+  let conversions = 0;
+  let activeCampaigns = 0;
+  const campaignRows: SmarketingCampaignRow[] = [];
+
+  for (const c of campaigns) {
+    const spent = Number(c.spent) || 0;
+    const budget = Number(c.budget) || 0;
+    const m = parseMetrics(c.metrics);
+    budgetTotal += budget;
+    spentTotal += spent;
+    impressions += m.impressions;
+    clicks += m.clicks;
+    conversions += m.conversions;
+    if (c.status === "active" || c.status === "running") activeCampaigns++;
+    campaignRows.push({
+      id: String(c.id),
+      name: String(c.name),
+      status: String(c.status),
+      spent,
+      conversions: m.conversions,
+      cpl: m.conversions > 0 ? spent / m.conversions : 0,
+    });
+  }
+
+  // ── Leads / contacts ──
+  const contacts = db
+    .prepare(`SELECT id, status FROM contacts`)
+    .all() as Record<string, unknown>[];
+  const byStatus: Record<string, number> = {};
+  for (const ct of contacts) {
+    const s = String(ct.status || "unknown");
+    byStatus[s] = (byStatus[s] || 0) + 1;
+  }
+  const totalContacts = contacts.length;
+  // MQL ≈ prospect + customer + evangelist (moved past raw lead); SQL ≈ contacts with ≥1 deal
+  const mql = totalContacts - (byStatus["lead"] || 0);
+  const contactIdsWithDeals = new Set(
+    (db.prepare(`SELECT DISTINCT contact_id FROM deals WHERE contact_id IS NOT NULL`).all() as Record<string, unknown>[]).map((d) => d.contact_id),
+  );
+  const sql = contacts.filter((ct) => contactIdsWithDeals.has(ct.id)).length;
+  const unworkedLeads = contacts.filter(
+    (ct) => String(ct.status) === "lead" && !contactIdsWithDeals.has(ct.id),
+  ).length;
+
+  // ── Sales: deals ──
+  const deals = db
+    .prepare(`SELECT id, value, stage, won_at, lost_at, updated_at, source FROM deals`)
+    .all() as Record<string, unknown>[];
+  const isWon = (d: Record<string, unknown>) => d.stage === "won" || d.stage === "closed-won";
+  const isLost = (d: Record<string, unknown>) => d.stage === "lost" || d.stage === "closed-lost";
+  const won = deals.filter(isWon);
+  const lost = deals.filter(isLost);
+  const open = deals.filter((d) => !isWon(d) && !isLost(d));
+  const wonValue = won.reduce((s, d) => s + (Number(d.value) || 0), 0);
+  const lostValue = lost.reduce((s, d) => s + (Number(d.value) || 0), 0);
+  const pipelineValue = open.reduce((s, d) => s + (Number(d.value) || 0), 0);
+  const decided = won.length + lost.length;
+  const winRate = decided > 0 ? Math.round((won.length / decided) * 100) : 0;
+  const avgDealSize = won.length > 0 ? Math.round(wonValue / won.length) : 0;
+  const staleOpenDeals = open.filter((d) => t - (Number(d.updated_at) || 0) > 14 * DAY).length;
+
+  // ── Attribution (marketing-sourced revenue) ──
+  const attr = attributionRollup("position_based");
+  const marketingSourcedRevenue = attr.total_attributed;
+  const marketingRoi = spentTotal > 0 ? marketingSourcedRevenue / spentTotal : 0;
+  const costPerAcquisition = won.length > 0 ? spentTotal / won.length : 0;
+  const cacPaybackRatio = costPerAcquisition > 0 && avgDealSize > 0 ? avgDealSize / costPerAcquisition : 0;
+
+  // ── Alignment rates ──
+  const leadToDealRate = totalContacts > 0 ? Math.round((sql / totalContacts) * 100) : 0;
+  const dealToWonRate = deals.length > 0 ? Math.round((won.length / deals.length) * 100) : 0;
+
+  // ── Deal risk (powered by deal-intel) ──
+  const riskScores = scoreAllDeals();
+  let safe = 0, watch = 0, atRisk = 0, critical = 0;
+  for (const r of riskScores) {
+    if (r.riskLevel === "safe") safe++;
+    else if (r.riskLevel === "watch") watch++;
+    else if (r.riskLevel === "at-risk") atRisk++;
+    else critical++;
+  }
+  const riskTop = riskScores.slice(0, 5).map((r) => {
+    const d = deals.find((x) => x.id === r.dealId) as Record<string, unknown> | undefined;
+    return {
+      dealId: r.dealId,
+      name: d ? String(d.title) : r.dealId,
+      value: d ? Number(d.value) || 0 : 0,
+      level: r.riskLevel,
+      risk: Math.round(r.risk * 100),
+    };
+  });
+
+  // ── Funnel: Leads → MQL → SQL → Customers (won deals) ──
+  const funnel: SmarketingFunnelStage[] = [
+    { key: "leads", label: "Leads", value: totalContacts },
+    { key: "mql", label: "MQL", value: mql },
+    { key: "sql", label: "SQL (with deal)", value: sql },
+    { key: "won", label: "Customers (won)", value: won.length },
+  ];
+
+  // ── Top campaigns by conversions ──
+  const topCampaigns = campaignRows
+    .sort((a, b) => b.conversions - a.conversions || b.spent - a.spent)
+    .slice(0, 8);
+
+  return {
+    generated_at: t,
+    marketing: {
+      campaigns_total: campaigns.length,
+      campaigns_active: activeCampaigns,
+      budget_total: budgetTotal,
+      spent_total: spentTotal,
+      impressions,
+      clicks,
+      conversions,
+      ctr: impressions > 0 ? Math.round((clicks / impressions) * 1000) / 10 : 0,
+      cpl: conversions > 0 ? Math.round((spentTotal / conversions) * 100) / 100 : 0,
+    },
+    sales: {
+      pipeline_value: pipelineValue,
+      won_value: wonValue,
+      lost_value: lostValue,
+      open_deals: open.length,
+      won_deals: won.length,
+      lost_deals: lost.length,
+      win_rate: winRate,
+      avg_deal_size: avgDealSize,
+    },
+    leads: { total: totalContacts, by_status: byStatus, mql, sql },
+    alignment: {
+      lead_to_deal_rate: leadToDealRate,
+      deal_to_won_rate: dealToWonRate,
+      marketing_sourced_revenue: marketingSourcedRevenue,
+      marketing_roi: Math.round(marketingRoi * 100) / 100,
+      cost_per_acquisition: Math.round(costPerAcquisition),
+      cac_payback_ratio: Math.round(cacPaybackRatio * 100) / 100,
+      unworked_leads: unworkedLeads,
+      stale_open_deals: staleOpenDeals,
+    },
+    funnel,
+    top_campaigns: topCampaigns,
+    risk: {
+      open: open.length,
+      safe,
+      watch,
+      atRisk,
+      critical,
+      top: riskTop,
+    },
+    channel_attribution: {
+      model: attr.model,
+      total_attributed: attr.total_attributed,
+      deals_attributed: attr.deals_attributed,
+      channels: attr.channel_credits.map((c) => ({
+        channel: c.channel,
+        credit: c.credit,
+        share: Math.round(c.share * 1000) / 10,
+      })),
+    },
+  };
+}

