input.content:
"use client";

import { useFetch } from "@/components/useFetch";
import { KpiCard } from "./KpiCard";
import { formatCurrency, formatNumber } from "@/lib/constants";
import {
  Handshake,
  Megaphone,
  Target,
  TrendingUp,
  Users,
  AlertTriangle,
  DollarSign,
} from "lucide-react";

type Metrics = {
  generated_at: number;
  marketing: Record<string, number>;
  sales: Record<string, number>;
  leads: { total: number; by_status: Record<string, number>; mql: number; sql: number };
  alignment: Record<string, number>;
  funnel: { key: string; label: string; value: number }[];
  top_campaigns: { id: string; name: string; status: string; spent: number; conversions: number; cpl: number }[];
  risk: {
    open: number;
    safe: number;
    watch: number;
    atRisk: number;
    critical: number;
    top: { dealId: string; name: string; value: number; level: string; risk: number }[];
  };
  channel_attribution: {
    model: string;
    total_attributed: number;
    deals_attributed: number;
    channels: { channel: string; credit: number; share: number }[];
  };
};

const RISK_COLOR: Record<string, string> = {
  safe: "#22c55e",
  watch: "#eab308",
  "at-risk": "#f97316",
  critical: "#ef4444",
};

export function SmarketingDashboard() {
  const { data, loading, error } = useFetch<Metrics>("/api/smarketing");

  if (loading) return <div className="text-sm muted">Loading Smarketing alignment…</div>;
  if (error || !data)
    return <div className="text-sm text-rose-600">Couldn’t load Smarketing data: {error}</div>;

  const m = data.marketing;
  const s = data.sales;
  const a = data.alignment;
  const maxFunnel = Math.max(...data.funnel.map((f) => f.value), 1);

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-3xl font-bold text-gray-900 flex items-center gap-2">
          <Handshake className="w-7 h-7 text-indigo-500" /> Smarketing
        </h1>
        <p className="mt-1 text-gray-600">
          Sales + Marketing alignment — one view of the lead → deal → revenue engine.
        </p>
      </div>

      {/* KPI grid */}
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4">
        <KpiCard
          label="Pipeline"
          value={formatCurrency(s.pipeline_value)}
          sub={`${s.open_deals} open deals`}
          icon={<Target className="w-4 h-4" />}
        />
        <KpiCard
          label="Won Revenue"
          value={formatCurrency(s.won_value)}
          sub={`${s.won_deals} won · ${s.win_rate}% win rate`}
          accent="#16a34a"
          icon={<DollarSign className="w-4 h-4" />}
        />
        <KpiCard
          label="Mktg Spend"
          value={formatCurrency(m.spent_total)}
          sub={`${m.campaigns_active} active / ${m.campaigns_total} campaigns`}
          icon={<Megaphone className="w-4 h-4" />}
        />
        <KpiCard
          label="Mktg-Sourced Rev"
          value={formatCurrency(a.marketing_sourced_revenue)}
          sub={`${data.channel_attribution.deals_attributed} attributed deals`}
          accent="#6366f1"
          icon={<TrendingUp className="w-4 h-4" />}
        />
        <KpiCard
          label="Mktg ROI"
          value={`${a.marketing_roi}x`}
          sub={`CAC payback ${a.cac_payback_ratio}x`}
          accent="#0ea5e9"
          icon={<TrendingUp className="w-4 h-4" />}
        />
        <KpiCard
          label="Leads"
          value={formatNumber(data.leads.total)}
          sub={`${data.leads.mql} MQL · ${data.leads.sql} SQL`}
          icon={<Users className="w-4 h-4" />}
        />
      </div>

      {/* Funnel */}
      <section className="rounded-xl border p-5 bg-white" style={{ borderColor: "rgb(var(--border))" }}>
        <h2 className="font-semibold mb-4">Lead → Revenue Funnel</h2>
        <div className="space-y-3">
          {data.funnel.map((f, i) => (
            <div key={f.key} className="flex items-center gap-3">
              <div className="w-32 text-sm font-medium text-slate-600 shrink-0">{f.label}</div>
              <div className="flex-1 h-8 rounded-lg bg-slate-100 overflow-hidden">
                <div
                  className="h-full flex items-center justify-end pr-3 text-xs font-semibold text-white"
                  style={{
                    width: `${Math.max(8, (f.value / maxFunnel) * 100)}%`,
                    background: `linear-gradient(90deg, hsl(${245 - i * 35}, 80%, 60%), hsl(${245 - i * 35}, 80%, 50%))`,
                  }}
                >
                  {formatNumber(f.value)}
                </div>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Alignment metrics */}
      <section className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <KpiCard label="Lead → Deal" value={`${a.lead_to_deal_rate}%`} sub="contacts with a deal" />
        <KpiCard label="Deal → Won" value={`${a.deal_to_won_rate}%`} sub="of all deals" />
        <KpiCard
          label="Unworked Leads"
          value={formatNumber(a.unworked_leads)}
          sub="raw leads, no deal yet"
          accent={a.unworked_leads > 0 ? "#f97316" : undefined}
          icon={<AlertTriangle className="w-4 h-4" />}
        />
        <KpiCard
          label="Stale Open Deals"
          value={formatNumber(a.stale_open_deals)}
          sub="no update in 14+ days"
          accent={a.stale_open_deals > 0 ? "#ef4444" : undefined}
          icon={<AlertTriangle className="w-4 h-4" />}
        />
      </section>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Top campaigns */}
        <section className="rounded-xl border p-5 bg-white" style={{ borderColor: "rgb(var(--border))" }}>
          <h2 className="font-semibold mb-4">Top Campaigns (by conversions)</h2>
          <table className="w-full text-sm">
            <thead>
              <tr className="text-left text-slate-500 border-b" style={{ borderColor: "rgb(var(--border))" }}>
                <th className="py-2 font-medium">Campaign</th>
                <th className="py-2 font-medium">Status</th>
                <th className="py-2 font-medium text-right">Spend</th>
                <th className="py-2 font-medium text-right">Conv.</th>
                <th className="py-2 font-medium text-right">CPL</th>
              </tr>
            </thead>
            <tbody>
              {data.top_campaigns.map((c) => (
                <tr key={c.id} className="border-b" style={{ borderColor: "rgb(var(--border))" }}>
                  <td className="py-2 font-medium truncate max-w-[140px]">{c.name}</td>
                  <td className="py-2 text-xs text-slate-500">{c.status}</td>
                  <td className="py-2 text-right">{formatCurrency(c.spent)}</td>
                  <td className="py-2 text-right">{formatNumber(c.conversions)}</td>
                  <td className="py-2 text-right">{c.cpl > 0 ? formatCurrency(c.cpl) : "—"}</td>
                </tr>
              ))}
              {data.top_campaigns.length === 0 && (
                <tr>
                  <td colSpan={5} className="py-6 text-center text-slate-400">No campaigns yet.</td>
                </tr>
              )}
            </tbody>
          </table>
        </section>

        {/* Channel attribution */}
        <section className="rounded-xl border p-5 bg-white" style={{ borderColor: "rgb(var(--border))" }}>
          <h2 className="font-semibold mb-1">Marketing Attribution</h2>
          <p className="text-xs text-slate-500 mb-4">
            Model: {data.channel_attribution.model} · {formatCurrency(data.channel_attribution.total_attributed)} attributed
          </p>
          <div className="space-y-2">
            {data.channel_attribution.channels.map((ch) => (
              <div key={ch.channel} className="flex items-center gap-3">
                <div className="w-28 text-sm text-slate-600 truncate">{ch.channel}</div>
                <div className="flex-1 h-3 rounded bg-slate-100 overflow-hidden">
                  <div className="h-full bg-indigo-500" style={{ width: `${ch.share}%` }} />
                </div>
                <div className="w-12 text-right text-xs font-semibold">{ch.share}%</div>
              </div>
            ))}
            {data.channel_attribution.channels.length === 0 && (
              <div className="py-6 text-center text-slate-400">No attribution data.</div>
            )}
          </div>
        </section>
      </div>

      {/* Deal risk */}
      <section className="rounded-xl border p-5 bg-white" style={{ borderColor: "rgb(var(--border))" }}>
        <div className="flex items-center justify-between mb-4">
          <h2 className="font-semibold">Deal Risk (Sales intelligence)</h2>
          <div className="flex gap-3 text-xs">
            <span className="text-emerald-600">● {data.risk.safe} safe</span>
            <span className="text-yellow-500">● {data.risk.watch} watch</span>
            <span className="text-orange-500">● {data.risk.atRisk} at-risk</span>
            <span className="text-rose-600">● {data.risk.critical} critical</span>
          </div>
        </div>
        <table className="w-full text-sm">
          <thead>
            <tr className="text-left text-slate-500 border-b" style={{ borderColor: "rgb(var(--border))" }}>
              <th className="py-2 font-medium">Deal</th>
              <th className="py-2 font-medium text-right">Value</th>
              <th className="py-2 font-medium text-right">Risk</th>
              <th className="py-2 font-medium">Level</th>
            </tr>
          </thead>
          <tbody>
            {data.risk.top.map((r) => (
              <tr key={r.dealId} className="border-b" style={{ borderColor: "rgb(var(--border))" }}>
                <td className="py-2 font-medium truncate max-w-[200px]">{r.name}</td>
                <td className="py-2 text-right">{formatCurrency(r.value)}</td>
                <td className="py-2 text-right">{r.risk}%</td>
                <td className="py-2">
                  <span
                    className="px-2 py-0.5 rounded text-xs font-semibold text-white"
                    style={{ background: RISK_COLOR[r.level] || "#64748b" }}
                  >
                    {r.level}
                  </span>
                </td>
              </tr>
            ))}
            {data.risk.top.length === 0 && (
              <tr>
                <td colSpan={4} className="py-6 text-center text-slate-400">No open deals to score.</td>
              </tr>
            )}
          </tbody>
        </table>
      </section>
    </div>
  );
}

