// ── Top campaigns by conversions ──
const topCampaigns = campaignRows
  .sort((a, b) => b.conversions - a.conversions || b.spent - a.spent)
  .slice(0, 8);

// ── Sabri Suby — "Sell Like Crazy": The Leak, The Gap & The Bridge ──
// THE LEAK: where money is bleeding out — lost deals + wasted spend + the
// stage with the worst conversion drop in the funnel.
const lostRevenue = lostValue;
const wastedSpend = mql > 0 ? Math.round((spentTotal * (unworkedLeads / Math.max(mql, 1)))) : 0;
// Funnel conversion drops
const funnelDrops: { key: string; label: string; drop: number; drop_pct: number }[] = [];
for (let i = 1; i < funnel.length; i++) {
  const prev = funnel[i - 1].value;
  const cur = funnel[i].value;
  const drop = prev - cur;
  funnelDrops.push({
    key: funnel[i].key,
    label: `${funnel[i - 1].label} → ${funnel[i].label}`,
    drop,
    drop_pct: prev > 0 ? Math.round((drop / prev) * 100) : 0,
  });
}
const leakiest = funnelDrops.slice().sort((a, b) => b.drop - a.drop)[0] || {
  key: "leads->mql",
  label: "Leads → MQL",
  drop: 0,
  drop_pct: 0,
};

// THE GAP: unrealized potential — the pipeline already in flight plus the
// gap between what's closing and what the avg deal size says it could be.
const avgDealSize = won.length > 0 ? Math.round(wonValue / won.length) : 0;
const unrealizedRevenue = open.length * avgDealSize;
const dealsToFillGap = avgDealSize > 0 ? Math.round(unrealizedRevenue / avgDealSize) : 0;

// THE BRIDGE: the machine to close it — ROI, CAC, follow-up fortune (revenue
// sitting in stale/open deals that good follow-up would convert), and a
// speed-to-lead proxy (avg days contacts wait before any deal is opened).
const followUpFortune = staleOpenDeals * avgDealSize;
let speedToLeadHours = 0;
const leadToDealTimes = db
  .prepare(`SELECT c.created_at AS c_at, MIN(d.created_at) AS d_at FROM contacts c JOIN deals d ON d.contact_id = c.id GROUP BY c.id`)
  .all() as { c_at: number; d_at: number }[];
if (leadToDealTimes.length > 0) {
  const totalHours = leadToDealTimes.reduce(
    (s, r) => s + ((Number(r.d_at) - Number(r.c_at)) / (1000 * 60 * 60)),
    0,
  );
  speedToLeadHours = Math.round(totalHours / leadToDealTimes.length);
}

// Value ladder: how many customers sit on each rung (by contact status).
const STATUS_RUNG: Record<string, string> = {
  lead: "Tripwire / Opt-in",
  prospect: "Core Offer",
  customer: "Profit Maximizer",
  evangelist: "Retention / Retention Scaling",
  churned: "Reactivation",
};
const valueLadder = Object.keys(STATUS_RUNG).map((rung) => ({
  rung,
  label: STATUS_RUNG[rung],
  customers: byStatus[rung] || 0,
}));

// Headline KPI: pick the most dramatic number to lead with.
let headlineLabel = "Marketing ROI";
let headlineValue = `${Math.round(marketingRoi * 100) / 100}x`;
let headlineTone: "leak" | "gap" | "bridge" = "bridge";
if (lostRevenue > wonValue && lostRevenue > 0) {
  headlineLabel = "The Leak — revenue lost";
  headlineValue = formatCurrencyForHeadline(lostRevenue);
  headlineTone = "leak";
} else if (unrealizedRevenue > wonValue && open.length > 0) {
  headlineLabel = "The Gap — pipeline in flight";
  headlineValue = formatCurrencyForHeadline(unrealizedRevenue);
  headlineTone = "gap";
}

return {

