input.content:
/**
 * GitHub adapter — search open-source marketing repos via the GitHub REST API.
 *
 * Uses GITHUB_TOKEN (or GH_TOKEN) if available for a higher rate limit
 * (5000/hr authenticated vs 60/hr unauthenticated). Stores metadata only
 * (no source code); license is recorded so the martech-stack surface can flag
 * what's vendorable.
 */
import { db, now, uid } from "@/lib/db";

const API = "https://api.github.com";

function authHeaders(): Record<string, string> {
  const token = process.env.GITHUB_TOKEN || process.env.GH_TOKEN;
  const h: Record<string, string> = {
    Accept: "application/vnd.github+json",
    "User-Agent": "marketing-hub-ingest",
  };
  if (token) h.Authorization = `Bearer ${token}`;
  return h;
}

/** Curated search queries that map to marketing categories. */
export const GITHUB_QUERIES: { q: string; category: string }[] = [
  { q: "awesome marketing", category: "list" },
  { q: "seo tools", category: "seo" },
  { q: "marketing attribution", category: "attribution" },
  { q: "web scraper marketing", category: "scrape" },
  { q: "email marketing open source", category: "email" },
  { q: "analytics marketing", category: "analytics" },
  { q: "social media marketing", category: "social" },
  { q: "content marketing cms", category: "content" },
  { q: "lead generation", category: "leads" },
  { q: "marketing automation", category: "automation" },
];

export interface GitHubRepo {
  id: string;
  full_name: string;
  description: string;
  url: string;
  homepage: string | null;
  stars: number;
  forks: number;
  language: string | null;
  license: string | null;
  topics: string[];
  open_issues: number;
  pushed_at: number | null;
}

export interface IngestSummary {
  fetched: number;
  errors: number;
  note: string;
}

function parseDate(s: string | null | undefined): number | null {
  if (!s) return null;
  const t = Date.parse(s);
  return Number.isNaN(t) ? null : t;
}

/** Search one query and upsert matching repos. Returns counts. */
async function searchAndStore(q: string, category: string): Promise<{ fetched: number; errors: number }> {
  let fetched = 0;
  let errors = 0;
  const url = `${API}/search/repositories?q=${encodeURIComponent(q)}&sort=stars&order=desc&per_page=30`;
  try {
    const res = await fetch(url, { headers: authHeaders() });
    if (res.status === 403) {
      // rate limited
      errors++;
      return { fetched, errors };
    }
    if (!res.ok) {
      errors++;
      return { fetched, errors };
    }
    const data = (await res.json()) as { items?: Record<string, unknown>[] };
    for (const item of data.items || []) {
      try {
        const repo: GitHubRepo = {
          id: `gh_${String(item.id)}`,
          full_name: String(item.full_name),
          description: String(item.description || ""),
          url: String(item.html_url),
          homepage: item.homepage ? String(item.homepage) : null,
          stars: Number(item.stargazers_count) || 0,
          forks: Number(item.forks_count) || 0,
          language: item.language ? String(item.language) : null,
          license: item.license && typeof item.license === "object" ? String((item.license as Record<string, unknown>).spdx_id || (item.license as Record<string, unknown>).name || "") : null,
          topics: Array.isArray(item.topics) ? (item.topics as string[]) : [],
          open_issues: Number(item.open_issues_count) || 0,
          pushed_at: parseDate(String(item.pushed_at)),
        };
        db.prepare(
          `INSERT OR REPLACE INTO ingest_github (id, full_name, description, url, homepage, stars, forks, language, license, topics, open_issues, pushed_at, fetched_at, category)
           VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?)`,
        ).run(
          repo.id,
          repo.full_name,
          repo.description,
          repo.url,
          repo.homepage,
          repo.stars,
          repo.forks,
          repo.language,
          repo.license,
          JSON.stringify(repo.topics),
          repo.open_issues,
          repo.pushed_at,
          now(),
          category,
        );
        // upsert into the shared search index
        db.prepare(
          `INSERT OR REPLACE INTO loot_index (id, kind, ref_id, title, haystack, year, category, created_at)
           VALUES (?,?,?,?,?,?,?,?)`,
        ).run(
          repo.id,
          "github",
          repo.id,
          repo.full_name,
          `${repo.full_name} ${repo.description} ${(repo.topics || []).join(" ")} ${repo.language || ""}`.toLowerCase(),
          repo.pushed_at ? new Date(repo.pushed_at).getFullYear() : 0,
          category,
          now(),
        );
        fetched++;
      } catch {
        errors++;
      }
    }
  } catch {
    errors++;
  }
  return { fetched, errors };
}

/** Run all curated GitHub searches. */
export async function ingestGitHub(): Promise<IngestSummary> {
  let fetched = 0;
  let errors = 0;
  for (const { q, category } of GITHUB_QUERIES) {
    const r = await searchAndStore(q, category);
    fetched += r.fetched;
    errors += r.errors;
    // politeness: 200ms between queries
    await new Promise((res) => setTimeout(res, 200));
  }
  const note = `${GITHUB_QUERIES.length} queries, ${fetched} repos stored`;
  db.prepare(
    `INSERT OR REPLACE INTO ingest_runs (source, last_run, fetched, errors, note) VALUES (?,?,?,?,?)`,
  ).run("github", now(), fetched, errors, note);
  return { fetched, errors, note };
}

/** List stored repos, optionally filtered by category, sorted by stars. */
export function listGitHubRepos(category?: string, limit = 50): GitHubRepo[] {
  const rows = category
    ? db.prepare(`SELECT * FROM ingest_github WHERE category = ? ORDER BY stars DESC LIMIT ?`).all(category, limit)
