input.content:
/**
 * RSS/web publications adapter — fetch marketing publications via RSS/Atom
 * feeds and cache articles in ingest_web (+ loot_index).
 *
 * Reuses the marketingDive scraper's politeness model: per-fetch timeout,
 * defensive parsing, idempotent upsert by URL. Stores metadata + a short
 * excerpt only (no full-text republication).
 */
import { db, now, uid } from "@/lib/db";

export interface WebArticle {
  id: string;
  url: string;
  source: string;
  title: string;
  author: string;
  summary: string;
  published_at: number | null;
  fetched_at: number;
  category: string;
}

export interface IngestSummary {
  fetched: number;
  errors: number;
  note: string;
}

/** Curated RSS feeds. Prefer RSS over HTML scraping. */
export const RSS_FEEDS: { url: string; source: string; category: string }[] = [
  { url: "https://blog.hubspot.com/marketing/rss.xml", source: "HubSpot", category: "marketing" },
  { url: "https://www.marketingdive.com/feeds/news", source: "Marketing Dive", category: "marketing" },
  { url: "https://neilpatel.com/feed", source: "Neil Patel", category: "seo" },
  { url: "https://www.searchenginejournal.com/feed/", source: "Search Engine Journal", category: "seo" },
  { url: "https://contentmarketinginstitute.com/feed/", source: "Content Marketing Institute", category: "content" },
  { url: "https://www.socialmediaexaminer.com/feed/", source: "Social Media Examiner", category: "social" },
  { url: "https://moz.com/feed", source: "Moz", category: "seo" },
  { url: "https://www.wordstream.com/blog/feed", source: "WordStream", category: "ads" },
];

/** Minimal RSS/Atom item parser (no DOM dependency — regex over the XML). */
interface ParsedItem {
  title: string;
  link: string;
  description: string;
  pubDate: number | null;
  author: string;
}

function stripTags(s: string): string {
  return s
    .replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, "$1")
    .replace(/<[^>]+>/g, "")
    .replace(/&[a-z]+;/g, " ")
    .trim();
}

function parseDate(s: string | null | undefined): number | null {
  if (!s) return null;
  const t = Date.parse(s);
  return Number.isNaN(t) ? null : t;
}

function parseFeed(xml: string, source: string): ParsedItem[] {
  const items: ParsedItem[] = [];
  // RSS <item> blocks
  const rssMatches = xml.match(/<item[\s\S]*?<\/item>/gi) || [];
  for (const block of rssMatches) {
    const pick = (re: RegExp): string | null => {
      const m = block.match(re);
      return m ? stripTags(m[1]) : null;
    };
    const title = pick(/<title[^>]*>([\s\S]*?)<\/title>/i) || "";
    const link = pick(/<link[^>]*>([\s\S]*?)<\/link>/i) || (() => {
      const m = block.match(/<link[^>]*href="([^"]+)"/i);
      return m ? m[1] : "";
    })();
    const description = pick(/<description[^>]*>([\s\S]*?)<\/description>/i) || "";
    const pubDate = parseDate(pick(/<pubDate[^>]*>([\s\S]*?)<\/pubDate>/i));
    const author = pick(/<(?:author|dc:creator)[^>]*>([\s\S]*?)<\/(?:author|dc:creator)>/i) || source;
    if (title && link) items.push({ title, link, description, pubDate, author });
  }
  // Atom <entry> blocks
  const atomMatches = xml.match(/<entry[\s\S]*?<\/entry>/gi) || [];
  for (const block of atomMatches) {
    const pick = (re: RegExp): string | null => {
      const m = block.match(re);
      return m ? stripTags(m[1]) : null;
    };
    const title = pick(/<title[^>]*>([\s\S]*?)<\/title>/i) || "";
    const link = (() => {
      const m = block.match(/<link[^>]*href="([^"]+)"/i);
      return m ? m[1] : "";
    })();
    const description = pick(/<summary[^>]*>([\s\S]*?)<\/summary>/i) || pick(/<content[^>]*>([\s\S]*?)<\/content>/i) || "";
    const pubDate = parseDate(pick(/<(?:published|updated)[^>]*>([\s\S]*?)<\/(?:published|updated)>/i));
    const author = pick(/<name[^>]*>([\s\S]*?)<\/name>/i) || source;
    if (title && link) items.push({ title, link, description, pubDate, author });
  }
  return items;
}

async function fetchFeed(feed: { url: string; source: string; category: string }): Promise<{ fetched: number; errors: number }> {
  let fetched = 0;
  let errors = 0;
  try {
    const res = await fetch(feed.url, {
      headers: { "User-Agent": "marketing-hub-ingest/1.0" },
      signal: AbortSignal.timeout(15000),
    });
    if (!res.ok) {
      errors++;
      return { fetched, errors };
    }
    const xml = await res.text();
    const items = parseFeed(xml, feed.source).slice(0, 20);
    for (const it of items) {
      try {
        const id = uid("web");
        const summary = it.description.slice(0, 400);
        db.prepare(
          `INSERT OR IGNORE INTO ingest_web (id, url, source, title, author, summary, published_at, fetched_at, category, raw)
           VALUES (?,?,?,?,?,?,?,?,?,?)`,
        ).run(id, it.link, feed.source, it.title, it.author, summary, it.pubDate, now(), feed.category, "");
        // upsert into shared index (only if newly inserted — url UNIQUE)
        db.prepare(
          `INSERT OR IGNORE INTO loot_index (id, kind, ref_id, title, haystack, year, category, created_at)
           VALUES (?,?,?,?,?,?,?,?)`,
        ).run(
          id,
          "web",
          id,
          it.title,
          `${it.title} ${summary} ${feed.source} ${feed.category}`.toLowerCase(),
          it.pubDate ? new Date(it.pubDate).getFullYear() : 0,
          feed.category,
          now(),
        );
        fetched++;
      } catch {
        errors++;
      }
    }
  } catch {
    errors++;
  }
  return { fetched, errors };
}

/** Fetch all configured RSS feeds. */
export async function ingestWeb(): Promise<IngestSummary> {
  let fetched = 0;
  let errors = 0;
  for (const feed of RSS_FEEDS) {
    const r = await fetchFeed(feed);
    fetched += r.fetched;
    errors += r.errors;
    await new Promise((res) => setTimeout(res, 200)); // politeness
  }
  const note = `${RSS_FEEDS.length} feeds, ${fetched} articles stored`;
  db.prepare(
    `INSERT OR REPLACE INTO ingest_runs (source, last_run, fetched, errors, note) VALUES (?,?,?,?,?)`,
  ).run("web", now(), fetched, errors, note);
  return { fetched, errors, note };
}

/** List cached articles. */
export function listWebArticles(category?: string, limit = 50): WebArticle[] {
  const rows = category
    ? db.prepare(`SELECT * FROM ingest_web WHERE category = ? ORDER BY COALESCE(published_at, fetched_at) DESC LIMIT ?`).all(category, limit)
