input.content:
/**
 * Competitive intel adapter — capture competitor landing pages, pricing pages,
 * and ad-library snapshots as text extracts in ingest_competitor (+ loot_index).
 *
 * Stores extracted text only (no full HTML republication). The competitor
 * targets are user-defined (seeded here); future versions read from a
 * competitor config table.
 */
import { db, now, uid } from "@/lib/db";

export interface CompetitorSnapshot {
  id: string;
  competitor: string;
  url: string;
  kind: "landing" | "ad" | "pricing" | "review" | "social";
  title: string;
  captured_at: number;
  snapshot_text: string;
}

export interface IngestSummary {
  fetched: number;
  errors: number;
  note: string;
}

/** Seed competitor targets. In production these come from the competitors table. */
export const COMPETITOR_TARGETS: { competitor: string; url: string; kind: CompetitorSnapshot["kind"] }[] = [
  { competitor: "HubSpot", url: "https://www.hubspot.com/pricing", kind: "pricing" },
  { competitor: "HubSpot", url: "https://www.hubspot.com/", kind: "landing" },
  { competitor: "Mailchimp", url: "https://mailchimp.com/pricing/", kind: "pricing" },
  { competitor: "Mailchimp", url: "https://mailchimp.com/", kind: "landing" },
  { competitor: "Salesforce", url: "https://www.salesforce.com/pricing/", kind: "pricing" },
  { competitor: "Semrush", url: "https://www.semrush.com/pricing/", kind: "pricing" },
];

function htmlToText(html: string): string {
  return html
    .replace(/<script[\s\S]*?<\/script>/gi, "")
    .replace(/<style[\s\S]*?<\/style>/gi, "")
    .replace(/<nav[\s\S]*?<\/nav>/gi, "")
    .replace(/<footer[\s\S]*?<\/footer>/gi, "")
    .replace(/<[^>]+>/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .slice(0, 4000);
}

function extractTitle(html: string): string {
  const m = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
  return m ? m[1].trim().slice(0, 200) : "";
}

async function capture(target: { competitor: string; url: string; kind: CompetitorSnapshot["kind"] }): Promise<{ fetched: number; errors: number }> {
  try {
    const res = await fetch(target.url, {
      headers: { "User-Agent": "marketing-hub-ingest/1.0" },
      signal: AbortSignal.timeout(15000),
    });
    if (!res.ok) return { fetched: 0, errors: 1 };
    const html = await res.text();
    const text = htmlToText(html);
    const title = extractTitle(html);
    const id = uid("comp");
    db.prepare(
      `INSERT INTO ingest_competitor (id, competitor, url, kind, title, captured_at, snapshot_text, extracted)
       VALUES (?,?,?,?,?,?,?,?)`,
    ).run(id, target.competitor, target.url, target.kind, title, now(), text, "{}");
    db.prepare(
      `INSERT OR IGNORE INTO loot_index (id, kind, ref_id, title, haystack, year, category, created_at)
       VALUES (?,?,?,?,?,?,?,?)`,
    ).run(id, "competitor", id, `${target.competitor} — ${target.kind}`, `${target.competitor} ${target.kind} ${title} ${text.slice(0, 500)}`.toLowerCase(), new Date().getFullYear(), target.kind, now());
    return { fetched: 1, errors: 0 };
  } catch {
    return { fetched: 0, errors: 1 };
  }
}

/** Capture all competitor targets. */
export async function ingestCompetitors(): Promise<IngestSummary> {
  let fetched = 0;
  let errors = 0;
  for (const t of COMPETITOR_TARGETS) {
    const r = await capture(t);
    fetched += r.fetched;
    errors += r.errors;
    await new Promise((res) => setTimeout(res, 200));
  }
  const note = `${COMPETITOR_TARGETS.length} targets, ${fetched} captured`;
  db.prepare(
    `INSERT OR REPLACE INTO ingest_runs (source, last_run, fetched, errors, note) VALUES (?,?,?,?,?)`,
  ).run("competitor", now(), fetched, errors, note);
  return { fetched, errors, note };
}

/** List competitor snapshots. */
export function listCompetitors(kind?: string, limit = 50): CompetitorSnapshot[] {
  const rows = kind
    ? db.prepare(`SELECT * FROM ingest_competitor WHERE kind = ? ORDER BY captured_at DESC LIMIT ?`).all(kind, limit)
    : db.prepare(`SELECT * FROM ingest_competitor ORDER BY captured_at DESC LIMIT ?`).all(limit);
  return (rows as Record<string, unknown>[]).map((r) => ({
    id: String(r.id),
    competitor: String(r.competitor),
    url: String(r.url),
    kind: String(r.kind) as CompetitorSnapshot["kind"],
    title: String(r.title || ""),
    captured_at: Number(r.captured_at) || 0,
    snapshot_text: String(r.snapshot_text || ""),
  }));
}

