/**
 * Ingest indexer — orchestrates the source adapters with lazy schema init,
 * mirroring the loot indexer pattern.
 */
import { db } from "@/lib/db";
import { migrateIngestTables } from "./migrations-ingest";
import { ingestGitHub, listGitHubRepos, ingestStatus as ghStatus } from "./github";
import { ingestWeb, listWebArticles, ingestStatus as webStatus } from "./rss";
import { ingestCompetitors, listCompetitors, ingestStatus as compStatus } from "./web";

let initialized = false;
function ensureSchema() {
  if (initialized) return;
  migrateIngestTables(db);
  initialized = true;
}

export type IngestSource = "web" | "github" | "competitor" | "all";

/** Run one or all ingest sources. */
export async function runIngest(source: IngestSource): Promise<{ source: string; result: { fetched: number; errors: number; note: string } }> {
  ensureSchema();
  switch (source) {
    case "github":
      return { source, result: await ingestGitHub() };
    case "web":
      return { source, result: await ingestWeb() };
    case "competitor":
      return { source, result: await ingestCompetitors() };
    case "all": {
      const gh = await ingestGitHub();
      const w = await ingestWeb();
      const c = await ingestCompetitors();
      return {
        source: "all",
        result: {
          fetched: gh.fetched + w.fetched + c.fetched,
          errors: gh.errors + w.errors + c.errors,
          note: `github(${gh.fetched}) web(${w.fetched}) competitor(${c.fetched})`,
        },
      };
    }
  }
}

/** Cross-source search via the shared loot_index. */
export function searchIngest(query: string, limit = 20): { kind: string; ref_id: string; title: string; category: string | null }[] {
  ensureSchema();
  const q = `%${query.toLowerCase()}%`;
  const rows = db
    .prepare(
      `SELECT kind, ref_id, title, category FROM loot_index
       WHERE kind IN ('web','github','competitor') AND haystack LIKE ?
       ORDER BY created_at DESC LIMIT ?`,
    )
    .all(q, limit) as Record<string, unknown>[];
  return rows.map((r) => ({
    kind: String(r.kind),
    ref_id: String(r.ref_id),
    title: String(r.title),
    category: r.category ? String(r.category) : null,
  }));
}

/** Status of every ingest source. */
export function ingestAllStatus(): { source: string; last_run: number; fetched: number; errors: number; note: string | null; row_count: number }[] {
  ensureSchema();
  const out: { source: string; last_run: number; fetched: number; errors: number; note: string | null; row_count: number }[] = [];
  const sources: { key: string; status: () => ReturnType<typeof ghStatus>; table: string }[] = [
    { key: "github", status: () => ghStatus("github"), table: "ingest_github" },
    { key: "web", status: () => webStatus("web"), table: "ingest_web" },
    { key: "competitor", status: () => compStatus("competitor"), table: "ingest_competitor" },
  ];
  for (const s of sources) {
    const st = s.status();
    let rowCount = 0;
    try {
      rowCount = (db.prepare(`SELECT COUNT(*) c FROM ${s.table}`).get() as { c: number }).c;
    } catch {
      rowCount = 0;
    }
    out.push({
      source: s.key,
      last_run: st?.last_run || 0,
      fetched: st?.fetched || 0,
      errors: st?.errors || 0,
      note: st?.note || null,
      row_count: rowCount,
    });
  }
  return out;
}

export { listGitHubRepos, listWebArticles, listCompetitors, ensureSchema };

