import { NextRequest } from "next/server";
import { json } from "@/lib/api-helpers";
import { runIngest, type IngestSource } from "@/lib/ingest";

export const dynamic = "force-dynamic";
export const maxDuration = 60;

/** POST /api/ingest/run?source=github|web|competitor|all — triggers a crawl. */
export async function POST(req: NextRequest) {
  try {
    const source = (new URL(req.url).searchParams.get("source") || "all") as IngestSource;
    if (!["github", "web", "competitor", "all"].includes(source)) {
      return json({ error: "Invalid source. Use github|web|competitor|all" }, 400);
    }
    const result = await runIngest(source);
    return json(result);
  } catch (e) {
    const message = e instanceof Error ? e.message : "Ingest run failed";
    return json({ error: message }, 500);
  }
}

