import { NextRequest } from "next/server";
import { json } from "@/lib/api-helpers";
import { searchIngest } from "@/lib/ingest";

export const dynamic = "force-dynamic";

/** GET /api/ingest/search?q=...&limit= — cross-source search via loot_index. */
export async function GET(req: NextRequest) {
  try {
    const sp = new URL(req.url).searchParams;
    const q = sp.get("q") || "";
    const limit = Math.min(Number(sp.get("limit") || 20), 100);
    if (!q) return json({ results: [], query: "" });
    return json({ results: searchIngest(q, limit), query: q });
  } catch (e) {
    const message = e instanceof Error ? e.message : "Ingest search failed";
    return json({ error: message }, 500);
  }
}

