import { NextRequest } from "next/server";
import { json } from "@/lib/api-helpers";
import { listGitHubRepos } from "@/lib/ingest";

export const dynamic = "force-dynamic";

/** GET /api/martech-stack?category=seo&limit=50 — open-source marketing tools catalog. */
export async function GET(req: NextRequest) {
  try {
    const sp = new URL(req.url).searchParams;
    const category = sp.get("category") || undefined;
    const limit = Math.min(Number(sp.get("limit") || 50), 200);
    return json({ tools: listGitHubRepos(category, limit) });
  } catch (e) {
    const message = e instanceof Error ? e.message : "Failed to load martech stack";
    return json({ error: message }, 500);
  }
}

