"use client";

import { useState } from "react";
import { useFetch } from "@/components/useFetch";
import { Search, Star, GitFork, ExternalLink, Tag } from "lucide-react";

type Repo = {
  id: string;
  full_name: string;
  description: string;
  url: string;
  homepage: string | null;
  stars: number;
  forks: number;
  language: string | null;
  license: string | null;
  topics: string[];
  category: string;
};

const CATEGORIES = ["", "seo", "email", "social", "content", "analytics", "attribution", "automation", "scrape", "leads", "list"];

export default function MartechStackPage() {
  const [cat, setCat] = useState("");
  const { data, loading, error } = useFetch<{ tools: Repo[] }>(`/api/martech-stack${cat ? `?category=${cat}` : ""}`);

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-6">
        <div>
          <h1 className="text-3xl font-bold text-gray-900 flex items-center gap-2">
            <Tag className="w-7 h-7 text-indigo-500" /> MarTech Stack
          </h1>
          <p className="mt-1 text-gray-600">
            Open-source marketing tooling catalog, sourced live from GitHub. Run{" "}
            <code className="text-xs bg-slate-100 px-1 rounded">POST /api/ingest/run?source=github</code> to refresh.
          </p>
        </div>

        <div className="flex flex-wrap gap-2">
          {CATEGORIES.map((c) => (
            <button
              key={c}
              onClick={() => setCat(c)}
              className={`px-3 py-1.5 text-xs font-semibold rounded-lg transition ${
                cat === c ? "bg-indigo-600 text-white" : "bg-white border text-slate-600 hover:bg-slate-50"
              }`}
            >
              {c || "All"}
            </button>
          ))}
        </div>

        {loading && <div className="text-sm text-slate-500">Loading tools…</div>}
        {error && <div className="text-sm text-rose-600">Error: {error}</div>}

        {data && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {data.tools.map((r) => (
              <a
                key={r.id}
                href={r.url}
                target="_blank"
                rel="noreferrer"
                className="bg-white border rounded-xl p-4 shadow-sm hover:shadow-md transition flex flex-col gap-2"
              >
                <div className="flex items-start justify-between gap-2">
                  <div className="font-bold text-sm text-gray-900 truncate">{r.full_name}</div>
                  <ExternalLink className="w-3.5 h-3.5 text-slate-400 shrink-0" />
                </div>
                <p className="text-xs text-slate-600 line-clamp-2">{r.description || "No description"}</p>
                <div className="flex flex-wrap gap-1 mt-1">
                  {r.topics.slice(0, 3).map((t) => (
                    <span key={t} className="text-[10px] bg-slate-100 text-slate-600 px-1.5 py-0.5 rounded">{t}</span>
                  ))}
                </div>
                <div className="flex items-center gap-3 text-xs text-slate-500 mt-auto pt-2 border-t">
                  <span className="flex items-center gap-1"><Star className="w-3 h-3 text-amber-500" /> {r.stars.toLocaleString()}</span>
                  <span className="flex items-center gap-1"><GitFork className="w-3 h-3" /> {r.forks}</span>
                  {r.language && <span className="text-indigo-500">{r.language}</span>}
                  {r.license && <span className="text-emerald-600 ml-auto">{r.license}</span>}
                </div>
              </a>
            ))}
            {data.tools.length === 0 && (
              <div className="col-span-full text-center text-slate-400 py-12">
                No tools yet. Run the GitHub ingest to populate.
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

