"use client";

import { useState } from "react";
import { useFetch } from "@/components/useFetch";
import { Crosshair, ExternalLink, RefreshCw } from "lucide-react";

type Snapshot = {
  id: string;
  competitor: string;
  url: string;
  kind: string;
  title: string;
  captured_at: number;
  snapshot_text: string;
};

const KINDS = ["", "pricing", "landing", "ad", "review", "social"];

export default function CompetitiveIntelPage() {
  const [kind, setKind] = useState("");
  const { data, loading, error } = useFetch<{ snapshots: Snapshot[] }>(`/api/competitive-intelligence${kind ? `?kind=${kind}` : ""}`);

  const competitors = data ? [...new Set(data.snapshots.map((s) => s.competitor))] : [];

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-6">
        <div className="flex items-start justify-between flex-wrap gap-3">
          <div>
            <h1 className="text-3xl font-bold text-gray-900 flex items-center gap-2">
              <Crosshair className="w-7 h-7 text-rose-500" /> Competitive Intelligence
            </h1>
            <p className="mt-1 text-gray-600">
              Competitor landing, pricing & ad snapshots. Run{" "}
              <code className="text-xs bg-slate-100 px-1 rounded">POST /api/ingest/run?source=competitor</code> to refresh.
            </p>
          </div>
        </div>

        <div className="flex flex-wrap gap-2">
          {KINDS.map((k) => (
            <button
              key={k}
              onClick={() => setKind(k)}
              className={`px-3 py-1.5 text-xs font-semibold rounded-lg transition ${
                kind === k ? "bg-rose-600 text-white" : "bg-white border text-slate-600 hover:bg-slate-50"
              }`}
            >
              {k || "All"}
            </button>
          ))}
        </div>

        {loading && <div className="text-sm text-slate-500">Loading snapshots…</div>}
        {error && <div className="text-sm text-rose-600">Error: {error}</div>}

        {data && (
          <div className="space-y-6">
            {competitors.map((comp) => {
              const shots = data.snapshots.filter((s) => s.competitor === comp);
              return (
                <div key={comp} className="bg-white border rounded-xl p-5 shadow-sm">
                  <h2 className="font-bold text-lg text-gray-900 mb-3">{comp}</h2>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {shots.map((s) => (
                      <div key={s.id} className="border rounded-lg p-3">
                        <div className="flex items-center justify-between mb-2">
                          <span className="text-[10px] font-bold uppercase tracking-wide bg-slate-100 text-slate-600 px-2 py-0.5 rounded">{s.kind}</span>
                          <a href={s.url} target="_blank" rel="noreferrer" className="text-slate-400 hover:text-indigo-500">
                            <ExternalLink className="w-3.5 h-3.5" />
                          </a>
                        </div>
                        <div className="text-sm font-medium text-gray-800 mb-1 truncate">{s.title || s.url}</div>
                        <p className="text-xs text-slate-500 line-clamp-4">{s.snapshot_text.slice(0, 400)}…</p>
                      </div>
                    ))}
                  </div>
                </div>
              );
            })}
            {data.snapshots.length === 0 && (
              <div className="text-center text-slate-400 py-12">
                No snapshots yet. Run the competitor ingest to capture them.
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

