import { NextRequest } from "next/server";
import { json } from "@/lib/api-helpers";
import { db } from "@/lib/db";

export const dynamic = "force-dynamic";

/**
 * GET /api/social — social listening feed.
 * Aggregates marketing publications (wire_articles + ingest_web) by category
 * to surface trending topics for social content planning.
 */
export async function GET(_req: NextRequest) {
  try {
    // Topic volume from publications
    const topics = (db
      .prepare(
        `SELECT category, COUNT(*) AS volume FROM (
           SELECT category FROM wire_articles
           UNION ALL
           SELECT category FROM ingest_web
         ) GROUP BY category ORDER BY volume DESC`,
      )
      .all() as { category: string; volume: number }[])
      .filter((t) => t.category);

    // Recent articles for the feed
    const feed = (db
      .prepare(
        `SELECT title, url, source, summary, category, COALESCE(published_at, fetched_at) AS ts FROM (
           SELECT title, url, source, summary, category, published_at, fetched_at, 'wire' AS origin FROM wire_articles
           UNION ALL
           SELECT title, url, source, summary, category, published_at, fetched_at, 'ingest' AS origin FROM ingest_web
         ) ORDER BY ts DESC LIMIT 30`,
      )
      .all() as { title: string; url: string; source: string; summary: string; category: string; ts: number }[])
      .map((r) => ({ ...r, origin: r.source }));

    return json({ topics, feed });
  } catch (e) {
    const message = e instanceof Error ? e.message : "Failed to load social feed";
    return json({ error: message }, 500);
  }
}

"use client";

import { useFetch } from "@/components/useFetch";
import { Share2, TrendingUp, ExternalLink } from "lucide-react";

type Topic = { category: string; volume: number };
type FeedItem = { title: string; url: string; source: string; summary: string; category: string; ts: number; origin: string };

export default function SocialPage() {
  const { data, loading, error } = useFetch<{ topics: Topic[]; feed: FeedItem[] }>("/api/social");
  const maxVol = data ? Math.max(...data.topics.map((t) => t.volume), 1) : 1;

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-6">
        <div>
          <h1 className="text-3xl font-bold text-gray-900 flex items-center gap-2">
            <Share2 className="w-7 h-7 text-sky-500" /> Social
          </h1>
          <p className="mt-1 text-gray-600">
            Social listening — trending marketing topics from across publications, ready to spin into posts.
          </p>
        </div>

        {loading && <div className="text-sm text-slate-500">Loading…</div>}
        {error && <div className="text-sm text-rose-600">Error: {error}</div>}

        {data && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            {/* Topic volume */}
            <div className="bg-white border rounded-xl p-5 shadow-sm">
              <h2 className="font-bold text-gray-900 mb-4 flex items-center gap-2">
                <TrendingUp className="w-4 h-4 text-sky-500" /> Trending Topics
              </h2>
              <div className="space-y-2">
                {data.topics.map((t) => (
                  <div key={t.category} className="flex items-center gap-3">
                    <div className="w-24 text-sm text-slate-600 capitalize truncate">{t.category}</div>
                    <div className="flex-1 h-6 rounded bg-slate-100 overflow-hidden">
                      <div className="h-full bg-sky-500 flex items-center justify-end pr-2 text-xs font-semibold text-white" style={{ width: `${Math.max(8, (t.volume / maxVol) * 100)}%` }}>
                        {t.volume}
                      </div>
                    </div>
                  </div>
                ))}
                {data.topics.length === 0 && <div className="text-sm text-slate-400">No topics yet.</div>}
              </div>
            </div>

            {/* Feed */}
            <div className="lg:col-span-2 bg-white border rounded-xl p-5 shadow-sm">
              <h2 className="font-bold text-gray-900 mb-4">Content Feed</h2>
              <div className="space-y-3">
                {data.feed.map((f, i) => (
                  <a key={i} href={f.url} target="_blank" rel="noreferrer" className="block border-b pb-3 last:border-0 hover:bg-slate-50 -mx-2 px-2 rounded transition">
                    <div className="flex items-center gap-2 text-xs text-slate-400 mb-1">
                      <span className="font-semibold text-sky-600">{f.source}</span>
                      <span className="capitalize bg-slate-100 px-1.5 rounded">{f.category}</span>
                      <ExternalLink className="w-3 h-3 ml-auto" />
                    </div>
                    <div className="text-sm font-medium text-gray-900">{f.title}</div>
                    <p className="text-xs text-slate-500 line-clamp-2 mt-0.5">{f.summary}</p>
                  </a>
                ))}
                {data.feed.length === 0 && <div className="text-sm text-slate-400">No articles yet. Run the web ingest to populate.</div>}
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

import { NextRequest } from "next/server";
import { json } from "@/lib/api-helpers";
import { db, now, uid } from "@/lib/db";

export const dynamic = "force-dynamic";

/** GET /api/content — list pillar content. POST — create. */
export async function GET(req: NextRequest) {
  try {
    const status = new URL(req.url).searchParams.get("status") || undefined;
    const rows = status
      ? db.prepare(`SELECT * FROM pillar_content WHERE status = ? ORDER BY COALESCE(occurred_at, created_at) DESC LIMIT 100`).all(status)
      : db.prepare(`SELECT * FROM pillar_content ORDER BY COALESCE(occurred_at, created_at) DESC LIMIT 100`).all();
    return json({ items: rows });
  } catch (e) {
    return json({ error: e instanceof Error ? e.message : "Failed" }, 500);
  }
}

export async function POST(req: NextRequest) {
  try {
    const body = await req.json();
    const id = uid("pillar");
    const t = now();
    db.prepare(
      `INSERT INTO pillar_content (id, title, source, raw_content, key_insights, status, source_url, notes, created_at, updated_at, workspace_id)
       VALUES (?,?,?,?,?,?,?,?,?,?,?)`,
    ).run(
      id,
      String(body.title || ""),
      String(body.source || "manual"),
      String(body.raw_content || ""),
      String(body.key_insights || ""),
      String(body.status || "draft"),
      String(body.source_url || ""),
      String(body.notes || ""),
      t,
      t,
      "default",
    );
    return json({ id }, 201);
  } catch (e) {
