input.content:
"use client";

import { useState } from "react";
import { useFetch } from "@/components/useFetch";
import { FileText, Plus, X } from "lucide-react";

type Item = {
  id: string;
  title: string;
  source: string;
  status: string;
  key_insights: string;
  source_url: string;
  created_at: number;
};

export default function ContentPage() {
  const { data, loading, error, reload } = useFetch<{ items: Item[] }>("/api/content");
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState({ title: "", source: "manual", key_insights: "", source_url: "", status: "draft" });
  const [saving, setSaving] = useState(false);

  const save = async () => {
    setSaving(true);
    try {
      await fetch("/api/content", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify(form) });
      setForm({ title: "", source: "manual", key_insights: "", source_url: "", status: "draft" });
      setShowForm(false);
      reload();
    } finally {
      setSaving(false);
    }
  };

  const STATUS_COLOR: Record<string, string> = { draft: "#94a3b8", research: "#0ea5e9", writing: "#f59e0b", published: "#22c55e" };

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold text-gray-900 flex items-center gap-2">
              <FileText className="w-7 h-7 text-emerald-500" /> Content
            </h1>
            <p className="mt-1 text-gray-600">Pillar content hub — plan, research, and track your content engine.</p>
          </div>
          <button onClick={() => setShowForm(!showForm)} className="flex items-center gap-1.5 bg-emerald-600 text-white text-sm font-semibold px-4 py-2 rounded-lg hover:bg-emerald-700">
            {showForm ? <X className="w-4 h-4" /> : <Plus className="w-4 h-4" />} {showForm ? "Cancel" : "New Pillar"}
          </button>
        </div>

        {showForm && (
          <div className="bg-white border rounded-xl p-5 shadow-sm space-y-3">
            <input className="w-full border rounded-lg px-3 py-2 text-sm" placeholder="Pillar title" value={form.title} onChange={(e) => setForm({ ...form, title: e.target.value })} />
            <div className="grid grid-cols-2 gap-3">
              <input className="border rounded-lg px-3 py-2 text-sm" placeholder="Source (manual/ingest)" value={form.source} onChange={(e) => setForm({ ...form, source: e.target.value })} />
              <select className="border rounded-lg px-3 py-2 text-sm" value={form.status} onChange={(e) => setForm({ ...form, status: e.target.value })}>
                <option value="draft">Draft</option>
                <option value="research">Research</option>
                <option value="writing">Writing</option>
                <option value="published">Published</option>
              </select>
            </div>
            <input className="w-full border rounded-lg px-3 py-2 text-sm" placeholder="Source URL" value={form.source_url} onChange={(e) => setForm({ ...form, source_url: e.target.value })} />
            <textarea className="w-full border rounded-lg px-3 py-2 text-sm" rows={3} placeholder="Key insights" value={form.key_insights} onChange={(e) => setForm({ ...form, key_insights: e.target.value })} />
            <button onClick={save} disabled={saving || !form.title} className="bg-emerald-600 text-white text-sm font-semibold px-4 py-2 rounded-lg disabled:opacity-50">
              {saving ? "Saving…" : "Save Pillar"}
            </button>
          </div>
        )}

        {loading && <div className="text-sm text-slate-500">Loading…</div>}
        {error && <div className="text-sm text-rose-600">Error: {error}</div>}

        {data && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {data.items.map((it) => (
              <div key={it.id} className="bg-white border rounded-xl p-4 shadow-sm">
                <div className="flex items-start justify-between gap-2 mb-2">
                  <div className="font-bold text-sm text-gray-900 line-clamp-2">{it.title || "Untitled"}</div>
                  <span className="text-[10px] font-bold uppercase px-2 py-0.5 rounded text-white shrink-0" style={{ background: STATUS_COLOR[it.status] || "#94a3b8" }}>{it.status}</span>
                </div>
                <div className="text-xs text-slate-400 mb-2">{it.source}</div>
                {it.key_insights && <p className="text-xs text-slate-600 line-clamp-3">{it.key_insights}</p>}
                {it.source_url && <a href={it.source_url} target="_blank" rel="noreferrer" className="text-xs text-emerald-600 hover:underline mt-2 inline-block">Source →</a>}
              </div>
            ))}
            {data.items.length === 0 && <div className="col-span-full text-center text-slate-400 py-12">No pillar content yet. Create one above.</div>}
          </div>
        )}
      </div>
    </div>
  );
}

