import { NextRequest } from "next/server";
import { json } from "@/lib/api-helpers";
import { db, now, uid } from "@/lib/db";

export const dynamic = "force-dynamic";

/** GET /api/positioning — list positioning statements. POST — create. */
export async function GET(_req: NextRequest) {
  try {
    const rows = db.prepare(`SELECT * FROM positioning_statements ORDER BY created_at DESC LIMIT 100`).all();
    return json({ items: rows });
  } catch (e) {
    return json({ error: e instanceof Error ? e.message : "Failed" }, 500);
  }
}

export async function POST(req: NextRequest) {
  try {
    const body = await req.json();
    const id = uid("pos");
    const t = now();
    db.prepare(
      `INSERT INTO positioning_statements (id, workspace, target, frame_of_reference, points_of_difference, reasons_to_believe, brand_character, one_word_positioning, notes, created_at, updated_at, workspace_id)
       VALUES (?,?,?,?,?,?,?,?,?,?,?,?)`,
    ).run(
      id, "default",
      String(body.target || ""), String(body.frame_of_reference || ""),
      String(body.points_of_difference || ""), String(body.reasons_to_believe || ""),
