input.content:
"use client";

import { useState } from "react";
import { useFetch } from "@/components/useFetch";
import { Compass, Plus, X } from "lucide-react";

type Item = {
  id: string;
  target: string;
  frame_of_reference: string;
  points_of_difference: string;
  reasons_to_believe: string;
  brand_character: string;
  one_word_positioning: string;
  notes: string;
};

export default function PositioningPage() {
  const { data, loading, error, reload } = useFetch<{ items: Item[] }>("/api/positioning");
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState({ target: "", frame_of_reference: "", points_of_difference: "", reasons_to_believe: "", brand_character: "", one_word_positioning: "", notes: "" });
  const [saving, setSaving] = useState(false);

  const save = async () => {
    setSaving(true);
    try {
      await fetch("/api/positioning", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify(form) });
      setForm({ target: "", frame_of_reference: "", points_of_difference: "", reasons_to_believe: "", brand_character: "", one_word_positioning: "", notes: "" });
      setShowForm(false);
      reload();
    } finally {
      setSaving(false);
    }
  };

  const field = (key: keyof typeof form, label: string) => (
    <div key={key}>
      <label className="text-xs font-semibold text-slate-500">{label}</label>
      <input className="w-full border rounded-lg px-3 py-2 text-sm mt-1" value={form[key]} onChange={(e) => setForm({ ...form, [key]: e.target.value })} />
    </div>
  );

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold text-gray-900 flex items-center gap-2">
              <Compass className="w-7 h-7 text-violet-500" /> Positioning
            </h1>
            <p className="mt-1 text-gray-600">Strategic positioning canvas — target, frame, differentiation, and proof.</p>
          </div>
          <button onClick={() => setShowForm(!showForm)} className="flex items-center gap-1.5 bg-violet-600 text-white text-sm font-semibold px-4 py-2 rounded-lg hover:bg-violet-700">
            {showForm ? <X className="w-4 h-4" /> : <Plus className="w-4 h-4" />} {showForm ? "Cancel" : "New Canvas"}
          </button>
        </div>

        {showForm && (
          <div className="bg-white border rounded-xl p-5 shadow-sm space-y-3">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
              {field("target", "Target audience")}
              {field("frame_of_reference", "Frame of reference (category)")}
              {field("points_of_difference", "Points of difference")}
              {field("reasons_to_believe", "Reasons to believe")}
              {field("brand_character", "Brand character")}
              {field("one_word_positioning", "One-word positioning")}
            </div>
            <button onClick={save} disabled={saving || !form.target} className="bg-violet-600 text-white text-sm font-semibold px-4 py-2 rounded-lg disabled:opacity-50">
              {saving ? "Saving…" : "Save Canvas"}
            </button>
          </div>
        )}

        {loading && <div className="text-sm text-slate-500">Loading…</div>}
        {error && <div className="text-sm text-rose-600">Error: {error}</div>}

        {data && (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {data.items.map((it) => (
              <div key={it.id} className="bg-white border rounded-xl p-5 shadow-sm space-y-3">
                {it.one_word_positioning && <div className="text-2xl font-black text-violet-600">{it.one_word_positioning}</div>}
                <div className="grid grid-cols-2 gap-3 text-xs">
                  <div><div className="font-bold text-slate-400 uppercase">Target</div><div className="text-slate-700">{it.target || "—"}</div></div>
                  <div><div className="font-bold text-slate-400 uppercase">Frame</div><div className="text-slate-700">{it.frame_of_reference || "—"}</div></div>
                  <div><div className="font-bold text-slate-400 uppercase">Difference</div><div className="text-slate-700">{it.points_of_difference || "—"}</div></div>
                  <div><div className="font-bold text-slate-400 uppercase">Proof</div><div className="text-slate-700">{it.reasons_to_believe || "—"}</div></div>
                </div>
                {it.brand_character && <div className="text-xs text-slate-500 pt-2 border-t">Character: {it.brand_character}</div>}
              </div>
            ))}
            {data.items.length === 0 && <div className="col-span-full text-center text-slate-400 py-12">No positioning canvases yet. Create one above.</div>}
          </div>
        )}
      </div>
    </div>
  );
}

