/**
 * Seed-surface framework — generic manual-entry surfaces backed by their own
 * SQLite table, created lazily via a self-healing migration.
 *
 * Each surface is identified by a slug (e.g. "podcast", "video") and has:
 *  - a dedicated table `seed_<slug>` (id, title, status, category, body, url,
 *    meta JSON, created_at, updated_at)
 *  - CRUD via listSeed/createSeed
 *  - a seed of realistic sample rows on first access
 *
 * This lets the 12 no-scrape-source surfaces ship now as manual-entry apps
 * with adapter hooks left for future ingest.
 */
import { db, now, uid } from "@/lib/db";

export interface SeedSurfaceConfig {
  slug: string;
  label: string;
  icon?: string;
  statuses: string[];
  categories: string[];
  seed: { title: string; status: string; category: string; body: string; url?: string; meta?: Record<string, unknown> }[];
}

export interface SeedRow {
  id: string;
  title: string;
  status: string;
  category: string;
  body: string;
  url: string;
  meta: Record<string, unknown>;
  created_at: number;
  updated_at: number;
}

const TABLE = (slug: string) => `seed_${slug.replace(/[^a-z0-9]/gi, "_").toLowerCase()}`;
const seeded = new Set<string>();

/** Lazily create the surface table + seed it once. */
export function ensureSeedSurface(cfg: SeedSurfaceConfig): void {
  const table = TABLE(cfg.slug);
  if (seeded.has(table)) return;
  db.exec(`
    CREATE TABLE IF NOT EXISTS ${table} (
      id TEXT PRIMARY KEY,
      title TEXT NOT NULL,
      status TEXT NOT NULL DEFAULT 'draft',
      category TEXT NOT NULL DEFAULT 'general',
      body TEXT NOT NULL DEFAULT '',
      url TEXT NOT NULL DEFAULT '',
      meta TEXT NOT NULL DEFAULT '{}',
      created_at INTEGER NOT NULL,
      updated_at INTEGER NOT NULL
    );
    CREATE INDEX IF NOT EXISTS idx_${table}_status ON ${table}(status);
    CREATE INDEX IF NOT EXISTS idx_${table}_cat ON ${table}(category);
  `);
  // seed once if empty
  const count = (db.prepare(`SELECT COUNT(*) c FROM ${table}`).get() as { c: number }).c;
  if (count === 0 && cfg.seed.length > 0) {
    const stmt = db.prepare(
      `INSERT INTO ${table} (id, title, status, category, body, url, meta, created_at, updated_at) VALUES (?,?,?,?,?,?,?,?,?)`,
    );
    const t = now();
    for (const s of cfg.seed) {
      stmt.run(uid(cfg.slug), s.title, s.status, s.category, s.body, s.url || "", JSON.stringify(s.meta || {}), t, t);
    }
  }
  seeded.add(table);
}

/** List rows for a surface. */
export function listSeed(slug: string, status?: string, limit = 100): SeedRow[] {
  const table = TABLE(slug);
  const rows = status
    ? db.prepare(`SELECT * FROM ${table} WHERE status = ? ORDER BY updated_at DESC LIMIT ?`).all(status, limit)
    : db.prepare(`SELECT * FROM ${table} ORDER BY updated_at DESC LIMIT ?`).all(limit);
  return (rows as Record<string, unknown>[]).map((r) => ({
    id: String(r.id),
    title: String(r.title),
    status: String(r.status),
    category: String(r.category),
    body: String(r.body || ""),
    url: String(r.url || ""),
    meta: (() => { try { return JSON.parse(String(r.meta || "{}")); } catch { return {}; } })(),
    created_at: Number(r.created_at) || 0,
    updated_at: Number(r.updated_at) || 0,
  }));
}

/** Create a row for a surface. */
export function createSeed(slug: string, input: { title: string; status?: string; category?: string; body?: string; url?: string; meta?: Record<string, unknown> }): string {
  const table = TABLE(slug);
  const id = uid(slug);
  const t = now();
  db.prepare(
    `INSERT INTO ${table} (id, title, status, category, body, url, meta, created_at, updated_at) VALUES (?,?,?,?,?,?,?,?,?)`,
  ).run(id, input.title, input.status || "draft", input.category || "general", input.body || "", input.url || "", JSON.stringify(input.meta || {}), t, t);
  return id;
}

